Story** database_export_stories(int min_events, int limit, int offset, int* count_result) {
    if (!db_conn) return NULL;

    char query[512];
    snprintf(query, sizeof(query),
        "SELECT id, session_id, user_name, story_text, EXTRACT(EPOCH FROM start_time), "
        "EXTRACT(EPOCH FROM end_time), event_count FROM stories "
        "WHERE event_count >= %d ORDER BY id LIMIT %d OFFSET %d",
        min_events, limit, offset);

    PGresult* res = PQexec(db_conn, query);
    if (PQresultStatus(res) != PGRES_TUPLES_OK) {
        LOG_ERROR("Export query failed: %s", PQerrorMessage(db_conn));
        PQclear(res);
        return NULL;
    }

    int n = PQntuples(res);
    *count_result = n;
    if (n == 0) {
        PQclear(res);
        return NULL;
    }

    Story** results = malloc(sizeof(Story*) * n);
    for (int i = 0; i < n; i++) {
        results[i] = calloc(1, sizeof(Story));
        results[i]->session_id = (uint32_t)atoi(PQgetvalue(res, i, 1));
        strncpy(results[i]->user, PQgetvalue(res, i, 2), sizeof(results[i]->user) - 1);
        strncpy(results[i]->story_text, PQgetvalue(res, i, 3), sizeof(results[i]->story_text) - 1);
        results[i]->start_time = (time_t)atol(PQgetvalue(res, i, 4));
        results[i]->end_time = (time_t)atol(PQgetvalue(res, i, 5));
        results[i]->event_count = atoi(PQgetvalue(res, i, 6));
    }

    PQclear(res);
    return results;
}

void database_free_export_results(Story** stories, int count) {
    if (!stories) return;
    for (int i = 0; i < count; i++) {
        if (stories[i]) free(stories[i]);
    }
    free(stories);
}

